#!/usr/bin/env python3
"""Build or validate the aggregate JIT-dequant bowl-probe admission sidecar."""

from __future__ import annotations

import argparse
import hashlib
import json
from pathlib import Path
from typing import Any


RUN_DIR = Path(".a0/runs/jit-dequant/real")
DEFAULT_OUTPUT = RUN_DIR / "qwen2.5-0.5b-instruct.aggregate.bowl-probe.admission.json"
SOURCE_PATHS = {
    "dev-fast": RUN_DIR / "qwen2.5-0.5b-instruct.dev-fast.bowl-probe.admission.json",
    "dev-balanced": RUN_DIR / "qwen2.5-0.5b-instruct.dev-balanced.bowl-probe.admission.json",
    "dev-strict": RUN_DIR / "qwen2.5-0.5b-instruct.dev-strict.bowl-probe.admission.json",
    "gamma-frontier": RUN_DIR / "qwen2.5-0.5b-instruct.gamma-frontier.bowl-probe.admission.json",
}

CERTIFICATE_VERSION = "gnosis.jit-dequant.bowl-probe.aggregate-admission.v1"
EXPECTED_CERTS = {
    "Gnosis.QualityMarginCacheAdmissibility",
    "Gnosis.EnergyMarginBridgeAdmissibility",
    "Gnosis.BasinSeparatrixAdmissibility",
    "Gnosis.JitDequantAdmissibility",
    "Gnosis.ConformalCoverageAdmissibility",
}
EXPECTED_SOURCE_PROFILES = {
    "dev-fast": "dev-fast",
    "dev-balanced": "dev-balanced",
    "dev-strict": "dev-strict",
    "gamma-frontier": "dev-strict",
}
EXPECTED_SOURCE_ADMITTED = {
    "dev-fast": True,
    "dev-balanced": True,
    "dev-strict": False,
}


def read_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        raise SystemExit(f"missing source artifact: {path}")
    return json.loads(path.read_text())


def sha256(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def validate_source_payload(label: str, payload: dict[str, Any], path: Path) -> None:
    if payload.get("tool") != "bowl-probe":
        raise SystemExit(f"{path}: tool must be bowl-probe")
    expected_profile = EXPECTED_SOURCE_PROFILES[label]
    if payload.get("quality_profile") != expected_profile:
        raise SystemExit(
            f"{path}: expected profile {expected_profile}, got {payload.get('quality_profile')}"
        )
    admission = payload.get("admission")
    if not isinstance(admission, dict) or not isinstance(admission.get("admitted"), bool):
        raise SystemExit(f"{path}: admission.admitted must be boolean")
    expected_admitted = EXPECTED_SOURCE_ADMITTED.get(label)
    if expected_admitted is not None and admission["admitted"] != expected_admitted:
        raise SystemExit(
            f"{path}: expected admission.admitted={expected_admitted}, "
            f"got {admission['admitted']}"
        )
    matrix = payload.get("matrix")
    if not isinstance(matrix, dict) or matrix.get("sample_rows", 0) <= 0:
        raise SystemExit(f"{path}: matrix.sample_rows must be positive")
    proof_modules = {
        item.get("module")
        for item in payload.get("proof_spine", [])
        if isinstance(item, dict)
    }
    missing = EXPECTED_CERTS - proof_modules
    if missing:
        raise SystemExit(f"{path}: missing proof modules: {sorted(missing)}")
    conformal = payload.get("conformal")
    rows = conformal.get("rows") if isinstance(conformal, dict) else None
    if not isinstance(rows, list) or not rows:
        raise SystemExit(f"{path}: conformal.rows must be non-empty")
    if label == "gamma-frontier":
        frontier = payload.get("gamma_frontier")
        if not isinstance(frontier, dict):
            raise SystemExit(f"{path}: gamma_frontier must be an object")
        frontier_rows = frontier.get("rows")
        if not isinstance(frontier_rows, list) or not frontier_rows:
            raise SystemExit(f"{path}: gamma_frontier.rows must be non-empty")
        for key in ("exact_conformal_min_multiplier", "first_admitted_multiplier"):
            value = frontier.get(key)
            if not isinstance(value, (int, float)) or value <= 0:
                raise SystemExit(f"{path}: gamma_frontier.{key} must be positive")


def source_record(label: str, path: Path, payload: dict[str, Any]) -> dict[str, Any]:
    admission = payload.get("admission", {})
    return {
        "label": label,
        "path": str(path),
        "sha256": sha256(path),
        "quality_profile": payload.get("quality_profile"),
        "matrix": payload.get("matrix"),
        "admitted": admission.get("admitted"),
        "e8_vs_cubic_pct": payload.get("quant_mse", {}).get("e8_vs_cubic_pct"),
    }


def source_set_sha256(sources: list[dict[str, Any]]) -> str:
    canonical = json.dumps(
        [
            {"label": source["label"], "sha256": source["sha256"]}
            for source in sources
        ],
        sort_keys=True,
        separators=(",", ":"),
    ).encode("utf-8")
    return hashlib.sha256(canonical).hexdigest()


def proof_spine_union(payloads: list[dict[str, Any]]) -> list[dict[str, str]]:
    modules: dict[str, str] = {}
    for payload in payloads:
        for item in payload.get("proof_spine", []):
            if isinstance(item, dict) and item.get("module"):
                modules[str(item.get("key", item["module"]))] = str(item["module"])
    return [
        {"key": key, "module": module}
        for key, module in sorted(modules.items(), key=lambda pair: pair[0])
    ]


def frontier_boundary_window(frontier: dict[str, Any]) -> list[dict[str, Any]]:
    rows = frontier.get("rows")
    if not isinstance(rows, list):
        return []
    first = frontier.get("first_admitted_multiplier")
    last = frontier.get("last_rejected_multiplier")
    if not isinstance(first, (int, float)) or not isinstance(last, (int, float)):
        return []
    low = last - 0.10
    high = first + 0.10
    window: list[dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        multiplier = row.get("multiplier")
        if not isinstance(multiplier, (int, float)) or multiplier < low or multiplier > high:
            continue
        window.append(
            {
                "multiplier": multiplier,
                "admitted": row.get("admitted"),
                "all_conformal_admit": row.get("all_conformal_admit"),
                "e8_energy_accept_ge_cubic": row.get("e8_energy_accept_ge_cubic"),
                "e8_accept_rate_l2": row.get("e8_accept_rate_l2"),
                "cubic_accept_rate_l2": row.get("cubic_accept_rate_l2"),
                "gamma": row.get("gamma"),
            }
        )
    return window


def build_aggregate() -> dict[str, Any]:
    payloads = {label: read_json(path) for label, path in SOURCE_PATHS.items()}
    for label, payload in payloads.items():
        validate_source_payload(label, payload, SOURCE_PATHS[label])
    balanced = payloads["dev-balanced"]
    frontier = payloads["gamma-frontier"].get("gamma_frontier")
    if not isinstance(frontier, dict):
        raise SystemExit("gamma-frontier report must include gamma_frontier")

    first_admitted = frontier.get("first_admitted_multiplier")
    exact_min = frontier.get("exact_conformal_min_multiplier")
    default_gate_admitted = bool(balanced.get("admission", {}).get("admitted"))
    frontier_selects_margin = isinstance(first_admitted, (int, float)) and first_admitted > 0
    aggregate_admitted = default_gate_admitted and frontier_selects_margin
    sources = [
        source_record(label, path, payloads[label])
        for label, path in SOURCE_PATHS.items()
    ]

    source_payloads = list(payloads.values())
    return {
        "certificateVersion": CERTIFICATE_VERSION,
        "model": "qwen2.5-0.5b-instruct",
        "tool": "bowl-probe-aggregate",
        "scope": "real admitted-model weights; embedding carrier plus gamma frontier",
        "admission": {
            "admitted": aggregate_admitted,
            "policy": "dev-balanced admitted && gamma_frontier.first_admitted_multiplier exists",
            "default_gate_profile": "dev-balanced",
            "default_gate_admitted": default_gate_admitted,
            "frontier_selects_margin": frontier_selects_margin,
            "strict_rejection_is_boundary_evidence": not bool(
                payloads["dev-strict"].get("admission", {}).get("admitted")
            ),
        },
        "runtimeMarginSelector": {
            "exact_conformal_min_multiplier": exact_min,
            "first_admitted_multiplier": first_admitted,
            "last_rejected_multiplier": frontier.get("last_rejected_multiplier"),
            "comfortable_default_multiplier": 2.0,
            "boundary_window": frontier_boundary_window(frontier),
        },
        "sources": sources,
        "sourceSetSha256": source_set_sha256(sources),
        "profileVerdicts": {
            label: {
                "admitted": payload.get("admission", {}).get("admitted"),
                "sample_rows": payload.get("matrix", {}).get("sample_rows"),
                "e8_vs_cubic_pct": payload.get("quant_mse", {}).get("e8_vs_cubic_pct"),
            }
            for label, payload in payloads.items()
        },
        "proof_spine": proof_spine_union(source_payloads),
    }


def validate(path: Path) -> None:
    payload = read_json(path)
    if payload.get("certificateVersion") != CERTIFICATE_VERSION:
        raise SystemExit(f"{path}: wrong certificateVersion")
    admission = payload.get("admission")
    if not isinstance(admission, dict) or not isinstance(admission.get("admitted"), bool):
        raise SystemExit(f"{path}: admission.admitted must be boolean")
    if not admission["admitted"]:
        raise SystemExit(f"{path}: aggregate admission must be true")
    selector = payload.get("runtimeMarginSelector")
    if not isinstance(selector, dict):
        raise SystemExit(f"{path}: missing runtimeMarginSelector")
    first = selector.get("first_admitted_multiplier")
    exact = selector.get("exact_conformal_min_multiplier")
    if not isinstance(first, (int, float)) or first <= 0:
        raise SystemExit(f"{path}: first_admitted_multiplier must be positive")
    if not isinstance(exact, (int, float)) or exact <= 0:
        raise SystemExit(f"{path}: exact_conformal_min_multiplier must be positive")
    sources = payload.get("sources")
    if not isinstance(sources, list) or len(sources) != len(SOURCE_PATHS):
        raise SystemExit(f"{path}: expected {len(SOURCE_PATHS)} sources")
    source_set = payload.get("sourceSetSha256")
    if not isinstance(source_set, str) or len(source_set) != 64:
        raise SystemExit(f"{path}: sourceSetSha256 must be a sha256 hex string")
    for source in sources:
        source_path = Path(source["path"])
        if not source_path.exists():
            raise SystemExit(f"{path}: source missing: {source_path}")
        source_hash = sha256(source_path)
        if source.get("sha256") != source_hash:
            raise SystemExit(f"{path}: source hash mismatch: {source_path}")
        label = source.get("label")
        if label not in SOURCE_PATHS:
            raise SystemExit(f"{path}: unexpected source label: {label}")
        validate_source_payload(str(label), read_json(source_path), source_path)
    if source_set != source_set_sha256(sources):
        raise SystemExit(f"{path}: sourceSetSha256 mismatch")
    boundary = selector.get("boundary_window")
    if not isinstance(boundary, list) or not boundary:
        raise SystemExit(f"{path}: runtimeMarginSelector.boundary_window must be non-empty")
    print(
        f"OK {path} admitted={admission['admitted']} "
        f"first_admitted_multiplier={first}"
    )


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--output", default=str(DEFAULT_OUTPUT))
    parser.add_argument("--validate-only", action="store_true")
    args = parser.parse_args()

    output = Path(args.output)
    if not args.validate_only:
        payload = build_aggregate()
        output.parent.mkdir(parents=True, exist_ok=True)
        output.write_text(json.dumps(payload, indent=2) + "\n")
        print(f"wrote {output}")
    validate(output)


if __name__ == "__main__":
    main()
